 1	import * as React from 'react';
 2	import { SearchResultItemType } from '@odf/mco/types';
 3	import { convertSearchResult } from '@odf/mco/utils';
 4	import { VirtualMachineModel } from '@odf/shared';
 5	import { getName, getNamespace } from '@odf/shared/selectors';
 6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 7	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Trans } from 'react-i18next';
 9	import { Modal, ModalVariant } from '@patternfly/react-core';
10	import { AppManagePoliciesModalBody } from './app-manage-policies-modal-body';
11	import { ModalViewContext } from './utils/reducer';
12	
13	export const AppManagePoliciesModal: React.FC<AppManagePoliciesModalProps> = ({
14	  resource,
15	  cluster,
16	  isOpen,
17	  close,
18	}) => {
19	  const { t } = useCustomTranslation();
20	  const [currentModalContext, setModalContext] = React.useState(
21	    ModalViewContext.MANAGE_POLICY_VIEW
22	  );
23	
24	  // Problem: Parsing runs on every render, even if the resource didn't change.
25	  // This causes performance issues and unnecessary recalculations.
26	  // Fix: useMemo ensures parsing only happens when 'resource' changes.
27	  const application = React.useMemo(
28	    () => ('apigroup' in resource ? convertSearchResult(resource) : resource),
29	    [resource]
30	  );
31	
32	  const applicationName = getName(application) ?? application?.['name'];
33	  const applicationNamespace =
34	    getNamespace(application) ?? application?.['namespace'];
35	
36	  const title =
37	    currentModalContext === ModalViewContext.ASSIGN_POLICY_VIEW
38	      ? application.kind === VirtualMachineModel.kind
39	        ? t('Enroll virtual machine')
40	        : t('Enroll managed application')
41	      : t('Manage disaster recovery');
42	
43	  const description = (
44	    <Trans t={t}>
45	      <strong>Application:</strong> {applicationName} (Namespace:{' '}
46	      {applicationNamespace})
47	    </Trans>
48	  );
49	
50	  return (
51	    <Modal
52	      title={title}
53	      description={description}
54	      variant={ModalVariant.large}
55	      isOpen={isOpen}
56	      aria-label="Manage policy modal"
57	      aria-describedby="manage-policy-modal"
58	      onClose={close}
59	    >
60	      <AppManagePoliciesModalBody
61	        application={application}
62	        cluster={cluster}
63	        setCurrentModalContext={setModalContext}
64	      />
65	    </Modal>
66	  );
67	};
68	
69	// ACM action custom plugin callback,
70	// For more: https://github.com/stolostron/console/blob/main/frontend/src/plugin-extensions/properties/actionExtensionProps.ts#L27
71	type AppManagePoliciesModalProps = {
72	  resource: K8sResourceCommon | SearchResultItemType;
73	  isOpen: boolean;
74	  close: () => void;
75	  // Specific field for the ACM VM list page
76	  cluster?: string;
77	};
78	
79	export default AppManagePoliciesModal;

